package com.hospital.management.dao.impl;
import com.hospital.management.util.DatabaseConnectionManager;import org.junit.jupiter.api.Test;import org.mockito.MockedStatic;import java.sql.*;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;
class RoleAndDepartmentDaoTest{
 @Test void roleLookupReturnsId()throws Exception{Connection c=mock(Connection.class);PreparedStatement p=mock(PreparedStatement.class);ResultSet r=mock(ResultSet.class);when(c.prepareStatement(anyString())).thenReturn(p);when(p.executeQuery()).thenReturn(r);when(r.next()).thenReturn(true);when(r.getLong(1)).thenReturn(2L);try(MockedStatic<DatabaseConnectionManager> m=mockStatic(DatabaseConnectionManager.class)){m.when(DatabaseConnectionManager::getConnection).thenReturn(c);assertEquals(2L,new RoleDaoImpl().findRoleIdByName(" doctor ").orElseThrow());}verify(p).setString(1,"doctor");}
 @Test void activeDepartmentLookupUsesStatusAndOrdering()throws Exception{Connection c=mock(Connection.class);PreparedStatement p=mock(PreparedStatement.class);ResultSet r=mock(ResultSet.class);when(c.prepareStatement(anyString())).thenReturn(p);when(p.executeQuery()).thenReturn(r);try(MockedStatic<DatabaseConnectionManager> m=mockStatic(DatabaseConnectionManager.class)){m.when(DatabaseConnectionManager::getConnection).thenReturn(c);assertTrue(new DepartmentDaoImpl().findActiveDepartments().isEmpty());}verify(c).prepareStatement(argThat(sql->sql.contains("STATUS='ACTIVE'")&&sql.contains("ORDER BY DEPARTMENT_NAME")));}
}
